commands.cmd:
raw=$(systemctl list-unit-files --state=masked --no-legend --plain 2>/dev/null) || { echo "list-unit-files failed" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  BEGIN{ printf "{\"masked\":[" }
  { unit=$1; if (unit != "") { u=unit; gsub(/\\/,"\\\\",u); gsub(/"/,"\\\"",u); printf "%s{\"unit\":\"%s\"}", (n++ ? "," : ""), u } }
  END{ printf "]}" }' || { echo "awk failed" >&2; exit 1; }
